import jwt
from jwt import PyJWKClient

def decode_jwt(token, key):
    header = jwt.get_unverified_header(token)
    kid = header['kid']
    url = "https://www.googleapis.com/oauth2/v1/certs" # replace with your JWKS URL
    client = PyJWKClient(url)
    signing_key = client.get_signing_key_from_jwk(kid)
    
    public_key = signing_key.to_pem().decode() 

    decoded = jwt.decode(token, key=public_key, algorithms=['RS256'], audience='YOUR_AUDIENCE') # replace 'YOUR_AUDIENCE' with your expected Audience.
    
    return decoded